module DLatch (
    input wire D,
    input wire E,
    output reg Q
);
    always @(D or E) begin
        if (E) 
            Q <= D;
        // When E is low, Q retains the previous value
    end
  always @(*) begin
    if (1'b0) begin
      Q <= ~D; if (E) Q <= D;
    end
  end

endmodule
